import{_ as e,o as a,c as r,ag as o}from"./chunks/framework.BYYsWsaA.js";const u=JSON.parse('{"title":"Charts & Pivot Tables","description":"","frontmatter":{},"headers":[],"relativePath":"guide/charts.md","filePath":"guide/charts.md"}'),s={name:"guide/charts.md"};function i(l,t,n,h,d,g){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="charts-pivot-tables" tabindex="-1">Charts &amp; Pivot Tables <a class="header-anchor" href="#charts-pivot-tables" aria-label="Permalink to &quot;Charts &amp; Pivot Tables&quot;">​</a></h1><p>Wafflebase includes built-in charts and pivot tables so you can visualize and summarize your data without leaving the spreadsheet.</p><h2 id="charts" tabindex="-1">Charts <a class="header-anchor" href="#charts" aria-label="Permalink to &quot;Charts&quot;">​</a></h2><h3 id="insert-a-chart" tabindex="-1">Insert a Chart <a class="header-anchor" href="#insert-a-chart" aria-label="Permalink to &quot;Insert a Chart&quot;">​</a></h3><ol><li>Select the data range you want to chart (include headers in the first row)</li><li>Click <strong>Insert</strong> &gt; <strong>Chart</strong> in the toolbar</li><li>A chart appears on your sheet with the editor panel open on the right</li></ol><h3 id="chart-types" tabindex="-1">Chart Types <a class="header-anchor" href="#chart-types" aria-label="Permalink to &quot;Chart Types&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Best For</th></tr></thead><tbody><tr><td><strong>Bar</strong></td><td>Comparing categories side by side</td></tr><tr><td><strong>Line</strong></td><td>Showing trends over time</td></tr><tr><td><strong>Area</strong></td><td>Trends with volume emphasis</td></tr><tr><td><strong>Pie</strong></td><td>Showing proportions of a whole</td></tr><tr><td><strong>Scatter</strong></td><td>Visualizing relationships between two numeric values</td></tr></tbody></table><h3 id="configure-your-chart" tabindex="-1">Configure Your Chart <a class="header-anchor" href="#configure-your-chart" aria-label="Permalink to &quot;Configure Your Chart&quot;">​</a></h3><p>The chart editor panel has two tabs:</p><p><strong>Setup</strong> — Choose the chart type, data range, X-axis column, and which columns to plot as series.</p><p><strong>Customize</strong> — Set the chart title, legend position (top, bottom, left, right, or hidden), toggle gridlines, and pick a color palette.</p><h3 id="move-and-resize" tabindex="-1">Move and Resize <a class="header-anchor" href="#move-and-resize" aria-label="Permalink to &quot;Move and Resize&quot;">​</a></h3><p>Drag the chart to reposition it on the sheet. Drag the edges or corners to resize.</p><h3 id="color-palettes" tabindex="-1">Color Palettes <a class="header-anchor" href="#color-palettes" aria-label="Permalink to &quot;Color Palettes&quot;">​</a></h3><p>Three built-in palettes are available:</p><ul><li><strong>Default</strong> — Adapts to light/dark theme</li><li><strong>Warm</strong> — Orange and earth tones</li><li><strong>Cool</strong> — Blue and teal tones</li></ul><h2 id="pivot-tables" tabindex="-1">Pivot Tables <a class="header-anchor" href="#pivot-tables" aria-label="Permalink to &quot;Pivot Tables&quot;">​</a></h2><p>Pivot tables let you summarize large datasets by grouping, filtering, and aggregating values — similar to Google Sheets pivot tables.</p><h3 id="create-a-pivot-table" tabindex="-1">Create a Pivot Table <a class="header-anchor" href="#create-a-pivot-table" aria-label="Permalink to &quot;Create a Pivot Table&quot;">​</a></h3><ol><li>Select a data range (first row must be headers)</li><li>Click <strong>Insert</strong> &gt; <strong>Pivot Table</strong></li><li>A new sheet is created with the pivot result, and the editor panel opens</li></ol><h3 id="configure-fields" tabindex="-1">Configure Fields <a class="header-anchor" href="#configure-fields" aria-label="Permalink to &quot;Configure Fields&quot;">​</a></h3><p>In the pivot editor panel, drag fields into these areas:</p><ul><li><strong>Rows</strong> — Group data by these columns (supports multi-level grouping)</li><li><strong>Columns</strong> — Create column headers from field values</li><li><strong>Values</strong> — Aggregated data (SUM, COUNT, COUNTA, AVERAGE, MIN, MAX)</li><li><strong>Filters</strong> — Filter source data before aggregation</li></ul><h3 id="refresh" tabindex="-1">Refresh <a class="header-anchor" href="#refresh" aria-label="Permalink to &quot;Refresh&quot;">​</a></h3><p>Pivot tables do not auto-update when source data changes. Click <strong>Refresh</strong> in the editor panel to recalculate.</p><h3 id="grand-totals" tabindex="-1">Grand Totals <a class="header-anchor" href="#grand-totals" aria-label="Permalink to &quot;Grand Totals&quot;">​</a></h3><p>Row and column grand totals are shown by default. Toggle them off in the editor panel if you don&#39;t need them.</p>',27)])])}const p=e(s,[["render",i]]);export{u as __pageData,p as default};
